<?php namespace App\Filament\Resources\IntensiMisaResource\Pages; use App\Filament\Resources\IntensiMisaResource; use Filament\Actions; use Filament\Resources\Pages\ListRecords; use Illuminate\Support\Facades\Artisan; use Filament\Notifications\Notification; class ListIntensiMisas extends ListRecords { protected static string $resource = IntensiMisaResource::class; protected function getHeaderActions(): array { return [Actions\Action::make("reset_minggu")->label("Reset Minggu Ini")->color("danger")->requiresConfirmation()->action(function() { Artisan::call("intensi:reset"); Notification::make()->title("Intensi berhasil diarsipkan")->success()->send(); }), Actions\CreateAction::make()]; } }